public class Qs41_FindMiddleNode {

    static class ListNode {
        int val;
        ListNode next;
        ListNode(int val) { this.val = val; }
    }

    public static void main(String[] args) {
        ListNode head = new ListNode(1);
        head.next = new ListNode(2);
        head.next.next = new ListNode(3);
        head.next.next.next = new ListNode(4);
        head.next.next.next.next = new ListNode(5);
        head.next.next.next.next.next = new ListNode(6);
        
        ListNode middle = middleNodeBeginner(head);
        
        System.out.print("Output: [");
        ListNode curr = middle;
        while (curr != null) {
            System.out.print(curr.val + (curr.next != null ? "," : ""));
            curr = curr.next;
        }
        System.out.println("]");
    }
    
    // O(N) Two-Pass logically competently string string efficiently stably securely
    public static ListNode middleNodeBeginner(ListNode head) {
        int length = 0;
        ListNode current = head;
        
        while (current != null) {
            length++;
            current = current.next;
        }
        
        int middleIndex = length / 2;
        current = head;
        
        for (int i = 0; i < middleIndex; i++) {
            current = current.next;
        }
        
        return current;
    }
}

